import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';

import type { EmailIntent } from './types';

const intentTools = {
  classifyIntent: {
    description: 'Classify email intent',
    parameters: z.object({
      intent: z.enum(['reply', 'forward', 'archive', 'delegate']),
      priority: z.enum(['low', 'medium', 'high', 'urgent']),
    }),
  },
};

export async function detectEmailIntent(emailContent: string) {
  const result = await streamText({
    model: openai('gpt-4o'),
    tools: {
      classifyIntent: intentTools.classifyIntent,
    },
    prompt: `Analyze this email and classify intent: ${emailContent}`,
  });

  return result;
}

import { generateText } from 'ai';
import { openai } from '@ai-sdk/openai';

export async function generateDraft({
  intent,
  conversationHistory,
  userTemplates,
  recipient,
}: {
  intent: EmailIntent;
  conversationHistory: string;
  userTemplates: string[];
  recipient: string;
}) {
  const result = await generateText({
    model: openai('gpt-4o'),
    system: `You are a professional email assistant. Generate appropriate draft for ${intent}. Match user's tone from templates.`,
    prompt: `History: ${conversationHistory}\nTemplates: ${userTemplates.join('\n')}\nTo: ${recipient}`,
    maxTokens: 1000,
  });

  return result.text;
}

import { streamText, tool } from 'ai';
import { z } from 'zod';

const analyzeAttachment = tool({
  description: 'Analyze email attachment',
  parameters: z.object({
    filename: z.string(),
    contentType: z.string(),
    summary: z.string().describe('Key points from attachment'),
    actionRequired: z.boolean(),
  }),
});

export async function processAttachments(attachments: Array<{filename: string; content: Buffer}>) {
  const result = await streamText({
    model: openai('gpt-4o'),
    tools: { analyzeAttachment },
    prompt: 'Process these email attachments and determine response actions',
    toolChoice: 'auto',
  });

  return result;
}

import { generateObject } from 'ai';
import { z } from 'zod';

const approvalSchema = z.object({
  safeToSend: z.boolean(),
  confidence: z.number().min(0).max(1),
  issues: z.array(z.string()),
  suggestedEdits: z.string().optional(),
});

export async function validateSend(draft: string, recipient: string) {
  const { object } = await generateObject({
    model: openai('gpt-4o'),
    schema: approvalSchema,
    prompt: `Validate this draft for sending to ${recipient}: ${draft}`,
  });

  return object;
}

