import { createVex } from '@vex_dev/sdk/server';
import { generateText } from 'ai';

const vex = createVex({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!,
});

export async function safeGenerateDraft(params: GenerateDraftParams) {
  const guardrail = await vex.guardrail('email-draft-safety', {
    rules: {
      pii: { entities: ['EMAIL_ADDRESS', 'PHONE_NUMBER', 'SSN'] },
      tone: { sentiment: 'positive|neutral', toxicity: '<0.1' },
      length: { min: 50, max: 2000 },
    },
  });

  const result = await generateText(params);
  const verified = await guardrail.verify({ input: params.prompt, output: result.text });

  if (!verified.pass) {
    throw new Error(`Draft failed verification: ${verified.issues.join(', ')}`);
  }

  return result;
}

import { createVex } from '@vex_dev/sdk/server';
import { streamText } from 'ai';

const vex = createVex({ /* config */ });

export async function safeStreamIntentDetection(emailContent: string) {
  const streamGuardrail = await vex.streamGuardrail('email-intent-stream', {
    windowSize: 50,
    rules: {
      hallucination: { probability: '<0.05' },
      pii: { blockOnMatch: true },
    },
  });

  const result = await streamText({
    model: openai('gpt-4o'),
    prompt: `Classify intent: ${emailContent}`,
  });

  return streamGuardrail.verifyStream(result.textStream);
}

import { createVex } from '@vex_dev/sdk/server';
import { generateObject } from 'ai';

const vex = createVex({ /* config */ });

export async function safeRecipientValidation(emailData: EmailData) {
  const schemaGuardrail = await vex.schemaGuardrail('email-recipient-schema', {
    schema: {
      recipientDomain: { pattern: '^(company\.com|partner\.org)$' },
      recipientCount: { max: 10 },
    },
    providers: ['openai', 'anthropic'],
  });

  const result = await generateObject({
    model: openai('gpt-4o'),
    schema: recipientSchema,
    prompt: `Validate recipients for: ${JSON.stringify(emailData)}`,
  });

  return schemaGuardrail.verify(result.object);
}
